        }

        .svg-base { fill: rgba(255,255,255,0.9); stroke: #333; stroke-width: 2; }
        .svg-tick { stroke: #333; stroke-width: 1; }
        .svg-tick-major { stroke: #333; stroke-width: 2; }
        .svg-text { font-size: 10px; text-anchor: middle; font-family: sans-serif; fill: #555; }

        /* Interactive Parts in SVG (Hidden highlight state by default) */
        .highlight-part {
            opacity: 0;
            transition: opacity 0.3s ease;
            pointer-events: none; 
        }

        /* Radio Button Logic (The Core Interaction) */
        input[type="radio"].control-state {
            display: none; /* Hide actual radios */
        }

        /* Buttons Styling */
        .btn-label {
            display: block;
            padding: 10px 15px;
            margin-bottom: 8px;
            background: #f0f0f0;
            border: 1px solid #ccc;
            border-radius: 4px;
            cursor: pointer;
            transition: all 0.2s;
            font-weight: bold;
            font-size: 14px;
        }

        .btn-label:hover {
            background: #e0e0e0;
        }

        /* Info Boxes */
        .info-box {
            display: none; /* Hidden by default */
            margin-top: 15px;
            padding: 10px;
            background-color: #e8f4fd;
            border-left: 4px solid #3498db;
            font-size: 14px;
            line-height: 1.4;
            animation: fadeIn 0.3s ease-in;
        }

        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(-5px); }
            to { opacity: 1; transform: translateY(0); }
        }

        /* --- INTERACTION LOGIC (CSS ONLY) --- */

        /* 1. Centro/Origen */
        #rad-centro:checked ~ .layout-grid .controls-col label[for="rad-centro"] {
            background-color: #e74c3c; color: white; border-color: #c0392b;
        }
        #rad-centro:checked ~ .layout-grid .controls-col .info-centro { display: block; }
        #rad-centro:checked ~ .layout-grid .graphic-col svg .hl-center { opacity: 1; }

        /* 2. Línea Base */
        #rad-base:checked ~ .layout-grid .controls-col label[for="rad-base"] {
            background-color: #2ecc71; color: white; border-color: #27ae60;
        }
        #rad-base:checked ~ .layout-grid .controls-col .info-base { display: block; }
        #rad-base:checked ~ .layout-grid .graphic-col svg .hl-base { opacity: 1; }

        /* 3. Escalas */
        #rad-escala:checked ~ .layout-grid .controls-col label[for="rad-escala"] {
            background-color: #9b59b6; color: white; border-color: #8e44ad;
        }
        #rad-escala:checked ~ .layout-grid .controls-col .info-escala { display: block; }
        #rad-escala:checked ~ .layout-grid .graphic-col svg .hl-scales { opacity: 1; }

        /* 4. Ejemplo Ángulo */
        #rad-angulo:checked ~ .layout-grid .controls-col label[for="rad-angulo"] {
            background-color: #f39c12; color: white; border-color: #d35400;
        }
        #rad-angulo:checked ~ .layout-grid .controls-col .info-angulo { display: block; }
        #rad-angulo:checked ~ .layout-grid .graphic-col svg .hl-angle { opacity: 1; }

